#[tokio::test]
async fn test_filesystem_provider_in_server() {
    let dir = create_test_filesystem();

    let provider = FilesystemProvider::new(dir.path())
        .with_prefix("data")
        .with_recursive(true)
        .build();

    let server = ServerBuilder::new("test", "1.0")
        .resource_provider(provider)
        .build();

    let resources = server.list_resources().await.unwrap();
    assert!(resources.resources.iter().any(|r| r.uri == "file://data/config.json"));
    assert!(resources.resources.iter().any(|r| r.uri == "file://data/readme.md"));
    assert!(resources.resources.iter().any(|r| r.uri == "file://data/templates/email.html"));
}

